### Using onRoute Hook to Conditionally Apply preHandler Authentication

Source: https://github.com/fastify/fastify/blob/main/fastify/docs/Guides/Plugins-Guide.md

Shows how to build a plugin that uses the onRoute hook to dynamically attach a preHandler (e.g., JWT verification) to specific routes based on route config options. This pattern is ideal for a JWT auth plugin: decorate the instance with your verify function, then use onRoute to automatically attach it as a preHandler only to routes that opt in via config.

```javascript
fastify.register((instance, opts, done) => {
  instance.decorate('util', (request, key, value) => { request[key] = value })

  function handler(request, reply, done) {
    instance.util(request, 'timestamp', new Date())
    done()
  }

  instance.addHook('onRoute', (routeOptions) => {
    if (routeOptions.config && routeOptions.config.useUtil === true) {
      // set or add our handler to the route preHandler hook
      if (!routeOptions.preHandler) {
        routeOptions.preHandler = [handler]
        return
      }
      if (Array.isArray(routeOptions.preHandler)) {
        routeOptions.preHandler.push(handler)
        return
      }
      routeOptions.preHandler = [routeOptions.preHandler, handler]
    }
  })

  instance.get('/plugin1', {config: {useUtil: true}}, (request, reply) => {
    reply.send(request)
  })

  instance.get('/plugin2', (request, reply) => {
    reply.send(request)
  })

  done()
})
```

